module top_module(
    adder,
    address,
    rst,
    clk,
);input clk;
input rst;
input [15:0] adder;
output [7:0] address;
reg   [15:0] count;
wire __address_tmp = count[15:8];
assign address[7:0] = __address_tmp;
always @(posedge clk or posedge rst) begin
    if (rst) begin
        count <= 0;
    end
    else
    begin
        count <= count + adder;    
    end
end
endmodule
